# [cfg (test)] mod tests { use super :: * ; # [doc = " A minimal but faithful synthetic sample matching the harness schema (the committed"] # [doc = " `tools/llm-harness/reports/*-report.json` shape). Used so the unit test is fully offline +"] # [doc = " deterministic and does not depend on a path outside the crate."] const SAMPLE : & str = r#"{
      "harness": "mycelium-llm-validation",
      "version": "0.1.0",
      "run_id": "20260617T182214Z",
      "mode": "mock",
      "timestamp_utc": "20260617T182214Z",
      "honesty_posture": {
        "never_silent": true,
        "guarantee_lattice": ["Exact", "Proven", "Empirical", "Declared"],
        "model_allowed_tags": ["Declared", "Empirical"],
        "vr5_rule": "Model-derived claims are Empirical or Declared — NEVER Proven or Exact."
      },
      "summary": {
        "overall": "MOCK", "total": 4, "pass": 1, "mock_pass": 3,
        "skip": 0, "fail": 0, "exit_code": 0, "mode": "mock", "model": null
      },
      "results": [
        {
          "id": "V-01-determinism", "status": "mock-PASS", "guarantee_tag": "Declared",
          "message": "[MOCK] Determinism simulated with fixture.",
          "detail": {"mode": "mock", "matched": true}
        },
        {
          "id": "V-04-latency-tokens", "status": "mock-PASS", "guarantee_tag": "Declared",
          "message": "[MOCK] latency simulated.",
          "detail": {"mode": "mock", "wall_seconds": 0.0,
                     "token_counts": {"prompt": 12, "generated": 7, "note": "Declared"}}
        }
      ]
    }"# ; # [test] fn parses_the_synthetic_sample_and_marks_it_synthetic () { let r = LlmReport :: from_json (SAMPLE) . expect ("parses") ; assert_eq ! (r . harness , "mycelium-llm-validation") ; assert_eq ! (r . version , "0.1.0") ; assert_eq ! (r . mode , "mock") ; assert ! (r . is_synthetic () , "a mock-mode report must be flagged synthetic") ; assert ! (r . provenance () . contains ("SYNTHETIC") , "provenance must surface the synthetic label: {}" , r . provenance ()) ; assert_eq ! (r . results . len () , 2) ; assert ! (r . honesty_posture . never_silent) ; } # [test] fn pulls_latency_and_token_counts_from_detail () { let r = LlmReport :: from_json (SAMPLE) . unwrap () ; let v4 = r . results . iter () . find (| v | v . id == "V-04-latency-tokens") . unwrap () ; assert_eq ! (v4 . wall_seconds () , Some (0.0) , "the mock sentinel 0.0 is surfaced, not dropped") ; assert_eq ! (v4 . token_counts () , Some ((Some (12) , Some (7)))) ; assert ! (v4 . is_mock () , "a mock-PASS result must be flagged mock") ; } # [test] fn a_real_report_is_not_flagged_synthetic () { let real = SAMPLE . replace ("\"mode\": \"mock\"" , "\"mode\": \"real\"") . replace ("\"overall\": \"MOCK\"" , "\"overall\": \"PASS\"") ; let r = LlmReport :: from_json (& real) . unwrap () ; assert ! (! r . is_synthetic () , "a real-mode report must NOT be flagged synthetic") ; assert ! (r . provenance () . contains ("real model run")) ; } # [test] fn malformed_json_is_an_explicit_error_not_a_silent_skip () { let err = LlmReport :: from_json ("{ not json") . unwrap_err () ; assert ! (matches ! (err , LlmIngestError :: Parse (_))) ; } # [test] fn the_committed_harness_sample_if_present_parses () { let candidates = ["../../tools/llm-harness/reports/20260617T182214Z-report.json" , "tools/llm-harness/reports/20260617T182214Z-report.json" ,] ; for c in candidates { let p = Path :: new (c) ; if p . is_file () { let r = LlmReport :: from_path (p) . unwrap_or_else (| e | panic ! ("the committed harness sample must parse: {e}")) ; assert_eq ! (r . harness , "mycelium-llm-validation") ; assert ! (r . is_synthetic () , "the committed sample is the mock fixture") ; return ; } } } # [doc = " A minimal but complete Grok synthetic sample matching the committed fixture"] # [doc = " (`crates/mycelium-bench/tests/SYNTHETIC-SAMPLE-grok-4.3-self-test.json`)."] # [doc = " Kept inline so the unit tests are fully offline and deterministic."] const GROK_SAMPLE : & str = r#"{
      "metadata": {
        "harness": "mycelium-grok-coauthor",
        "version": "0.1.0",
        "model": "grok-4.3",
        "mode": "self-test",
        "endpoint": "mock (offline)",
        "task_set_id": "gold-compose-v1",
        "seed": 42,
        "max_rounds": 3,
        "timestamp_utc": "SAMPLE-DETERMINISTIC"
      },
      "honesty_posture": {
        "never_silent": true,
        "guarantee_lattice": ["Exact", "Proven", "Empirical", "Declared"],
        "model_allowed_tags": ["Empirical", "Declared"],
        "vr5_rule": "Model-derived claims are Empirical or Declared — NEVER Proven or Exact.",
        "synthetic": true,
        "synthetic_note": "SYNTHETIC (self-test): offline mock. NOT real model quality."
      },
      "quality": {
        "total": 2,
        "scored": 2,
        "skipped": 0,
        "syntactic_valid": 2,
        "typecheck_pass": 2,
        "syntactic_validity_rate": 1.0,
        "typecheck_pass_rate": 1.0,
        "edit_to_fix_iterations": [1, 1],
        "mean_edit_to_fix": 1.0
      },
      "performance": {
        "prompt_tokens": 100,
        "completion_tokens": 50,
        "total_tokens": 150,
        "total_cost_usd": 0.0002,
        "request_count": 2,
        "batch_count": 0,
        "mean_latency_s": 0.0,
        "total_latency_s": 0.0
      },
      "outcomes": [
        {
          "task_id": "g01",
          "spec": "identity",
          "model": "grok-4.3",
          "status": "PASS",
          "guarantee_tag": "Declared",
          "iterations_to_clean": 1,
          "rounds": [
            {"attempt": 1, "is_correction": false, "verdict": "clean",
             "syntactic_valid": true, "typecheck_pass": true,
             "prompt_tokens": 60, "completion_tokens": 25, "latency_s": 0.0,
             "cost_usd": 0.00014, "chat_ok": true, "chat_error": "", "diagnostics": []}
          ],
          "total_prompt_tokens": 60,
          "total_completion_tokens": 25,
          "total_latency_s": 0.0,
          "total_cost_usd": 0.00014,
          "message": "clean on first attempt"
        },
        {
          "task_id": "g04",
          "spec": "widen",
          "model": "grok-4.3",
          "status": "PASS",
          "guarantee_tag": "Declared",
          "iterations_to_clean": 1,
          "rounds": [
            {"attempt": 1, "is_correction": false, "verdict": "clean",
             "syntactic_valid": true, "typecheck_pass": true,
             "prompt_tokens": 40, "completion_tokens": 25, "latency_s": 0.0,
             "cost_usd": 0.00006, "chat_ok": true, "chat_error": "", "diagnostics": []}
          ],
          "total_prompt_tokens": 40,
          "total_completion_tokens": 25,
          "total_latency_s": 0.0,
          "total_cost_usd": 0.00006,
          "message": "clean on first attempt"
        }
      ],
      "ablation": {
        "experiment": "test ablation",
        "model": "grok-4.3",
        "task_set_id": "gold-compose-v1",
        "seeds": [1, 2],
        "arms": [],
        "retention": {"determinate": false}
      }
    }"# ; # [test] fn grok_schema_parses_and_marks_synthetic () { let g = GrokLlmReport :: from_json (GROK_SAMPLE) . expect ("grok sample parses") ; assert_eq ! (g . metadata . harness , "mycelium-grok-coauthor") ; assert_eq ! (g . metadata . model , "grok-4.3") ; assert_eq ! (g . metadata . mode , "self-test") ; assert ! (g . honesty_posture . never_silent) ; assert ! (g . honesty_posture . synthetic , "synthetic flag must be set") ; assert ! (g . is_synthetic () , "a self-test Grok report must be flagged synthetic") ; assert ! (g . provenance () . contains ("SYNTHETIC") , "provenance must surface the synthetic label: {}" , g . provenance ()) ; assert_eq ! (g . outcomes . len () , 2) ; } # [test] fn grok_deny_unknown_fields_catches_drift () { let mut v : serde_json :: Value = serde_json :: from_str (GROK_SAMPLE) . expect ("base Grok sample is valid") ; v . as_object_mut () . expect ("root is an object") . insert ("extra_key" . into () , serde_json :: json ! ("drift")) ; let drifted = serde_json :: to_string (& v) . expect ("re-serialize") ; let err = GrokLlmReport :: from_json (& drifted) . unwrap_err () ; assert ! (matches ! (err , LlmIngestError :: Parse (_)) , "unknown root field must be a parse error, not silent: {err}") ; GrokLlmReport :: from_json (GROK_SAMPLE) . expect ("the un-drifted base sample parses") ; } # [test] fn grok_accepts_null_ablation_and_null_mean_latency () { let mut v : serde_json :: Value = serde_json :: from_str (GROK_SAMPLE) . expect ("base Grok sample is valid") ; let root = v . as_object_mut () . expect ("root is an object") ; root . insert ("ablation" . into () , serde_json :: Value :: Null) ; root . get_mut ("performance") . and_then (serde_json :: Value :: as_object_mut) . expect ("performance is an object") . insert ("mean_latency_s" . into () , serde_json :: Value :: Null) ; let text = serde_json :: to_string (& v) . expect ("re-serialize") ; let g = GrokLlmReport :: from_json (& text) . expect ("null ablation + null mean_latency must ingest") ; assert ! (g . ablation . is_none () , "null ablation -> None") ; assert ! (g . performance . mean_latency_s . is_none () , "null mean_latency_s -> None") ; let parsed = parse_any_llm_json (& text , "grok-null.json" . into ()) . expect ("null-field Grok dispatches") ; assert ! (parsed . is_synthetic) ; } # [test] fn parse_any_dispatches_bench_schema_without_metadata_key () { let parsed = parse_any_llm_json (SAMPLE , "sample.json" . into ()) . expect ("bench sample dispatches correctly") ; assert ! (! parsed . validations . is_empty ()) ; assert ! (parsed . is_synthetic , "mock bench report is synthetic") ; assert ! (parsed . provenance . contains ("SYNTHETIC")) ; } # [test] fn parse_any_dispatches_grok_schema_with_metadata_key () { let parsed = parse_any_llm_json (GROK_SAMPLE , "grok-sample.json" . into ()) . expect ("grok sample dispatches correctly") ; assert_eq ! (parsed . validations . len () , 2 , "two outcomes → two rows") ; assert ! (parsed . is_synthetic , "self-test Grok report is synthetic") ; assert ! (parsed . provenance . contains ("SYNTHETIC")) ; for row in & parsed . validations { assert_eq ! (row . guarantee_tag . as_deref () , Some ("Declared") , "guarantee_tag must be preserved from the Grok outcome: {}" , row . id) ; } } # [test] fn parse_any_malformed_json_is_loud () { let err = parse_any_llm_json ("{ not json" , "x.json" . into ()) . unwrap_err () ; assert ! (matches ! (err , LlmIngestError :: Parse (_))) ; } }
